# write_query_clients.ps1 - run once from inside RAG-BANK:
#     powershell -ExecutionPolicy Bypass -File .\write_query_clients.ps1
$ErrorActionPreference = 'Stop'
$b64 = ''
$path = Join-Path (Get-Location) 'src/query_clients.py'
[System.IO.File]::WriteAllBytes($path, [System.Convert]::FromBase64String($b64))
Write-Host "wrote src/query_clients.py" -ForegroundColor Green
